/// Test enums matching the Zod reference fixtures
enum UserRole { admin, user, guest }

enum Status { active, inactive, pending }

/// Normalizes Zod fixtures by removing JavaScript-specific constraints.
///
/// This function recursively removes JavaScript safe integer bounds
/// (Number.MIN/MAX_SAFE_INTEGER) which don't apply to Dart's arbitrary precision integers.
Map<String, Object?> normalizeZodFixture(
  Map<String, Object?> zodSchema, {
  String? fixtureName,
}) {
  final normalized = Map<String, Object?>.from(zodSchema);

  // Remove $schema field if present (not part of core schema structure)
  normalized.remove('\$schema');

  // Helper to remove JS safe bounds from a schema
  void removeSafeBounds(Map<String, Object?> schema) {
    if (schema['type'] == 'integer') {
      if (schema['minimum'] == -9007199254740991) {
        schema.remove('minimum');
      }
      if (schema['maximum'] == 9007199254740991) {
        schema.remove('maximum');
      }
    }
  }

  // Remove bounds from root schema
  removeSafeBounds(normalized);

  if (normalized.isEmpty) {
    return _canonicalAnySchema(normalized);
  }

  if (fixtureName != null && fixtureName.startsWith('any-')) {
    return _canonicalAnySchema(normalized);
  }

  // Handle anyOf patterns (e.g., nullable integers, nested anyOf)
  if (normalized['anyOf'] is List) {
    final anyOf = normalized['anyOf'] as List;
    for (var i = 0; i < anyOf.length; i++) {
      final option = anyOf[i];
      if (option is Map<String, Object?>) {
        // Recursively normalize the entire anyOf option
        anyOf[i] = normalizeZodFixture(option);
      }
    }
  }

  if (fixtureName == 'anyof-nullable') {
    _flattenNullableAnyOf(normalized);
  }

  // Handle array item schemas
  if (normalized['items'] is Map<String, Object?>) {
    normalized['items'] = normalizeZodFixture(
      normalized['items'] as Map<String, Object?>,
    );
  }

  // Handle object property schemas
  if (normalized['properties'] is Map<String, Object?>) {
    final props = normalized['properties'] as Map<String, Object?>;
    props.forEach((key, value) {
      if (value is Map<String, Object?>) {
        props[key] = normalizeZodFixture(value);
      }
    });

    if (props.isEmpty) {
      normalized.remove('properties');
    } else {
      normalized['propertyOrdering'] = props.keys.toList();
    }
  }

  if (normalized['additionalProperties'] is Map<String, Object?> &&
      (normalized['additionalProperties'] as Map<String, Object?>).isEmpty) {
    normalized['additionalProperties'] = true;
  }

  if (fixtureName != null && fixtureName.startsWith('discriminated-')) {
    return _canonicalDiscriminatedSchema(normalized);
  }

  return normalized;
}

Map<String, Object?> _canonicalAnySchema(Map<String, Object?> schema) {
  final description = schema['description'] as String?;
  final branches = [
    for (final type in [
      'string',
      'number',
      'integer',
      'boolean',
      'object',
      'array',
    ])
      {'type': type, if (description != null) 'description': description},
  ];

  return {
    if (description != null) 'description': description,
    if (schema.containsKey('default')) 'default': schema['default'],
    'anyOf': [
      ...branches,
      if (schema['anyOf'] case final List<Object?> anyOf
          when anyOf.any((branch) => branch is Map && branch['type'] == 'null'))
        {'type': 'null'},
    ],
  };
}

void _flattenNullableAnyOf(Map<String, Object?> schema) {
  if (schema['anyOf'] case [
    final Map<String, Object?> inner,
    final nullBranch,
  ] when inner['anyOf'] is List) {
    schema['anyOf'] = [...(inner['anyOf'] as List<Object?>), nullBranch];
  }
}

Map<String, Object?> _canonicalDiscriminatedSchema(
  Map<String, Object?> schema,
) {
  final description = schema['description'];
  final branches = _extractDiscriminatedBranches(schema);
  final discriminator = _inferDiscriminatorProperty(branches);

  return {
    if (description != null) 'description': description,
    'oneOf': branches,
    'discriminator': {'propertyName': discriminator},
  };
}

List<Object?> _extractDiscriminatedBranches(Map<String, Object?> schema) {
  final anyOf = schema['anyOf'] as List<Object?>;
  if (anyOf case [
    final Map<String, Object?> inner,
    final Map nullBranch,
  ] when inner['anyOf'] is List && nullBranch['type'] == 'null') {
    return [
      ...(inner['anyOf'] as List<Object?>),
      nullBranch.cast<String, Object?>(),
    ];
  }
  return anyOf;
}

String _inferDiscriminatorProperty(List<Object?> branches) {
  for (final branch in branches) {
    if (branch is! Map<String, Object?> || branch['type'] == 'null') {
      continue;
    }
    final properties = branch['properties'];
    if (properties is! Map<String, Object?>) continue;
    for (final entry in properties.entries) {
      final property = entry.value;
      if (property is Map<String, Object?> && property.containsKey('const')) {
        return entry.key;
      }
    }
  }
  throw StateError('Could not infer discriminator property from fixture.');
}

/// Loads a reference JSON Schema fixture generated by Zod.
///
/// Fixtures are located in `tools/test-fixtures/reference-schemas/`.
/// The loaded fixture is automatically normalized to remove JavaScript-specific constraints.
Map<String, Object?> loadReferenceFixture(String name) {
  // Navigate from packages/ack to project root (../../)
  final currentDir = Directory.current.path;
  final projectRoot = currentDir.endsWith('/packages/ack')
      ? currentDir.substring(0, currentDir.length - '/packages/ack'.length)
      : currentDir;
  final fixturePath =
      '$projectRoot/tools/test-fixtures/reference-schemas/$name.json';
  final file = File(fixturePath);

  if (!file.existsSync()) {
    throw Exception(
      'Reference fixture not found: $fixturePath\n'
      'Make sure to run: npm run fixtures (from tools/ directory)',
    );
  }

  final content = file.readAsStringSync();
  final zodSchema = jsonDecode(content) as Map<String, Object?>;

  // Normalize Zod fixtures to remove JS-specific constraints
  return normalizeZodFixture(zodSchema, fixtureName: name);
}
